<template>
    <BaseModal
        name="setup-reaction"
        :mobileMode="true"
        :closeOutside="true"
        :isLoading="data.loading"
    >
        <template v-slot:content>
            <div class="reaction-setup">
                <!-- 1. Слоты выбранных стикеров -->
                <div class="values">
                    <div 
                        v-for="i in data.reactionCount" 
                        :key="`slot-${i}`"
                        :class="{ 'is-filled': data.values[i - 1] }"
                        @click="removeValue(i - 1)"
                    >
                        <template v-if="data.values[i - 1]">
                            <TgsViewer 
                                :url="getTgsUrl(data.values[i - 1].collection, data.values[i - 1].code)" 
                                :size="48" 
                            />
                            <div class="remove">
                                <Icon icon="close" />
                            </div>
                        </template>

                        <Icon icon="plus" class="empty" v-else />
                    </div>
                </div>

                <!-- 2. Сетка стикеров текущей коллекции -->
                <div class="options" ref="scrollContainer">
                    <ul>
                        <li 
                            v-for="item in data.items" 
                            :key="item.code"
                            v-intersection-observer="onIntersection"
                            :data-code="item.code"
                            @click="selectItem(item)"
                        >
                            <TgsViewer 
                                v-if="visibleItems[item.code]"
                                :url="getTgsUrl(data.collection, item.code)" 
                                :size="64"
                            />
                        </li>
                    </ul>
                </div>

                <!-- 3. Таббар выбора коллекций -->
                <div class="collections-nav">
                    <ul>
                        <li 
                            v-for="item in data.collections" 
                            :key="item.code"
                            :class="{ 'is-active': data.collection === item.code }"
                            @click="changeCollection(item.code)"
                        >
                            <div :style="{ '--icon-url': `url(${collectionUrl}/${item.code}/icon.svg)` }"
                            ></div>
                        </li>
                    </ul>
                </div>

                <div class="buttons">
                    <Button :name="t('common.save')"
                        @click="save"
                    />
                    <Button :name="t('common.close')"
                        class="secondary"
                        @click="close"
                    />
                </div>
            </div>
        </template>
    </BaseModal>
</template>

<script setup>
import { onMounted, reactive, ref, nextTick } from 'vue';
import { useI18n } from 'vue-i18n';

import BaseModal from '🔗/components/modals/BaseModal.vue';
import TgsViewer from '🔗/components/ui/TgsViewer.vue';
import Icon from '🔗/components/ui/Icon.vue';
import Button from '🔗/components/ui/Button.vue';
import stores from '@/stores';
import api from '🔗/api';
import { REACTIONS_BY_ENTITY } from '🔗/constants';

const { t } = useI18n();
const modals = stores.modals();

const collectionUrl = import.meta.env.VITE_APP_TGS_URL;
const scrollContainer = ref(null);

const data = reactive({
    loading: true,
    collection: null,
    collections: [], // [{ code, icon }, ...]
    items: [], // [{ code }, ...]
    reactionCount: 4, // Сколько слотов для выбора стикеров
    values: [], // [{ collection - код коллекции, code - код tgs внутри коллекции }, ...]
});

const visibleItems = reactive({});

const getTgsUrl = (col, code) => `${collectionUrl}/${col}/${code}.tgs`;

// Оптимизация: рендерим TGS только когда li виден
const onIntersection = ([{ isIntersecting, target }]) => {
    const code = target.dataset.code;
    if (isIntersecting && !visibleItems[code]) {
        visibleItems[code] = true;
    }
};

const selectItem = (payload) => {
    const isDuplicate = data.values.some(item => item.code === payload.code && item.collection === data.collection);
    
    if (isDuplicate) {
        return;
    }

    if (data.values.length < data.reactionCount) {
        data.values.push({
            collection: data.collection,
            code: payload.code
        });
    }
};

const removeValue = (index) => {
    if (data.values[index]) {
        data.values.splice(index, 1);
    }
};

const changeCollection = async (code) => {
    if (data.collection === code) {
        return;
    }

    data.collection = code;

    if (scrollContainer.value) {
        scrollContainer.value.scrollTop = 0;
    }

    // Очищаем видимые элементы для новой коллекции
    Object.keys(visibleItems).forEach(key => delete visibleItems[key]);
    await getItems();
};

const getItems = async () => {
    data.items = await api.tgs().getCollection(data.collection) || [];
};

const save = async () => {
    data.loading = true;
    // console.log({
    //     field: data.field,
    //     entityType: data.entityType,
    //     entityId: data.entityId,
    //     values: data.values,
    // });

    await api.entity().owner(data.entityType, data.entityId, data.field, JSON.stringify({
        values: data.values
    }))
    // console.log('Saved Reaction Settings:', [...data.values]);
    modals.close('setup-reaction');
};

const close = () => {
    modals.close('setup-reaction');
};

onMounted(async () => {
    const payload = modals.getData('setup-reaction');

    if (!payload?.code || !payload?.entityType || !payload?.entityId) {
        close();
        return;
    }

    data.entityType = payload.entityType;
    data.entityId = payload.entityId;

    // Получаем настройку конкретной реакции для конкретной сущности
    const settings = REACTIONS_BY_ENTITY[payload?.entityType]?.find(item => item.code === payload?.code);
    if (!settings?.reactionCount) {
        close();
        return;
    }
    data.reactionCount = settings.reactionCount;
    data.field = settings.field;

    // Получаем список коллекций
    data.collections = await api.tgs().getCollections() || [];
    if (!data.collections?.length) {
        close();
        return;
    }
    data.collection = data.collections[0].code;

    // Получаем стикеры этой коллекции
    await getItems();

    // Получаем текущие значения сущности
    const result = await api.entity().owner(data.entityType, data.entityId, data.field)

    if (result) {
        try {
            data.values = JSON.parse(result)?.values || [];
        } catch (e) {
        }
    }

    data.loading = false;
});
</script>

<style lang="scss" scoped>
.reaction-setup {
    display: flex;
    flex-direction: column;
    height: 70vh;
    padding: 0;
    gap: 0;

    .values {
        display: flex;
        justify-content: space-around;
        background: var(--dark-5);
        padding: 8px 0;
        border-radius: 8px;

        & > div {
            width: 64px;
            height: 64px;
            border-radius: 12px;
            background: var(--dark-10);
            border: 2px dashed var(--dark-10);
            display: flex;
            align-items: center;
            justify-content: center;
            position: relative;
            transition: all 0.2s ease;

            &.is-filled {
                border-style: solid;
                background: var(--white-500);
            }

            .empty {
                fill: var(--dark-20);
                width: 20px;
                height: 20px;
            }

            .remove {
                position: absolute;
                top: 0px;
                right: 2px;
                border-radius: 50%;
                width: 16px;
                height: 16px;
                display: flex;
                align-items: center;
                justify-content: center;

                svg {
                    width: 10px;
                    height: 10px;
                    fill: var(--dark-20);
                }
            }
        }
    }

    .options {
        flex: 1;
        overflow-y: auto;
        margin: 0;

        & > ul {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 4px;
            list-style: none;
            padding: 0;

            & > li {
                aspect-ratio: 1;
                border-radius: 10px;
                display: flex;
                align-items: center;
                justify-content: center;
                cursor: pointer;
                min-height: 72px; /* Важно для Intersection Observer */

                transition: transform 0.2s cubic-bezier(0.33, 1, 0.68, 1), 
                background-color 0.2s ease;

                &:active {
                    transform: scale(0.92);
                    background: var(--dark-5);
                }

                /* Чтобы TgsViewer внутри тоже плавно появлялся, если он в v-if */
                :deep(canvas), :deep(svg) {
                    animation: fade-in 0.3s ease-out;
                }
            }
        }
    }

    .collections-nav {
        padding: 18px 0;
        
        & > ul {
            display: flex;
            gap: 20px;
            overflow-x: auto;
            list-style: none;
            padding: 0;
            scrollbar-width: none;
            margin: 0;

            &::-webkit-scrollbar { display: none; }

            & > li {
                flex-shrink: 0;
                width: 32px;
                height: 32px;
                opacity: 0.8;
                transition: opacity 0.3s;
                border-radius: 8px;
                display: flex;
                align-items: center;
                justify-content: center;

                &.is-active {
                    opacity: 1;
                    // transform: scale(1.2);
                    background: var(--dark-10);
                    & > div {
                        width: 24px;
                        height: 24px;
                    }
                }

                & > div {
                    width: 18px;
                    height: 18px;
                    background-color: var(--dark-90);
                    -webkit-mask-image: var(--icon-url);
                    mask-image: var(--icon-url);
                    -webkit-mask-repeat: no-repeat;
                    mask-repeat: no-repeat;
                    -webkit-mask-size: contain;
                    mask-size: contain;
                    mask-position: center;
                }
            }
        }
    }

    .buttons {
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 100%;
        z-index: 1;
        flex: 0;
        gap: 10px;

        button {
            width: 100%;
            flex-shrink: 0;
        }
    }
}
</style>
